/**
 * 조회 기본값 설정
 */
scwin.f_SetSrchDefault = function () {
  scwin.closeYm = $c.date.getServerDateTime($p).substring(0, 6);
  ica_fromDate.setValue(scwin.closeYm);
  ed_sacctDeptCd.setValue("");
  ed_sacctDeptNm.setValue("");
  $c.gus.cfEnableObjects($p, [ed_sacctDeptCd, ed_sacctDeptNm]);
  scwin.f_LoadVer();
  ica_fromDate.focus();
};

/**
 * Ver정보를 가져온다.
 */
scwin.f_LoadVer = async function () {
  console.log("=== f_LoadVer (Ver정보 조회)");

  //작업구분코드 및 날짜 세팅함수 호출
  scwin.f_setWrkNoFromDate();
  dma_search.set("sysCd", "CommonEBC");
  dma_search.set("queryId", "retrieveVersionInfo");
  dma_search.set("param1", ica_fromDate.getValue());
  ds_version.setJSON([]);
  let e = await $c.sbm.execute($p, sbm_retrieveCommonPopup);
  if (e.responseJSON.resultDataSet[0].Code != 0) return;
  ds_version.setJSON(e.responseJSON.GAUCE);
  ds_version.reform();
  await scwin.f_SetFinalVer();
};

/**
 * 최종 Ver을 설정
 */
scwin.f_SetFinalVer = async function () {
  console.log("=== f_SetFinalVer (최종 Ver 설정)");
  if (ds_version.getRowCount() < 1) return;
  let index = 0;
  for (let i = 0; i < ds_version.getRowCount(); i++) {
    if (ds_version.getCellData(i, "col3") == scwin.DGlobalValue.TRUE) {
      index = i;
      console.log("  최종 버전 [" + i + "]  col3 [" + ds_version.getCellData(i, "col3") + "]  col1-col2-col4 [" + ds_version.getCellData(i, "col1") + "][" + ds_version.getCellData(i, "col2") + "][" + ds_version.getCellData(i, "col4") + "]");
      break;
    }
  }
  lc_version.setSelectedIndex(index);

  // KYU_MOVE
  lc_version.hidVal = lc_version.getValue();
  console.log("  onUdcCompleted   버전hid [" + lc_version.hidVal + "] 년월hid [" + ica_fromDate.hidVal + "]");
};

// @@ ====== 조회 ============================================================================== //

/**
 * 조회필드 CLEAR
 */
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tbl_search, [ed_coCd, ed_coNm, ica_fromDate, lc_version, ed_sacctDeptCd, ed_sacctDeptNm]);
  //dma_search.setJSON(scwin.initJson);
  scwin.f_SetSrchDefault();
};

/**
* 조회버튼
*/
scwin.f_Retrieve = async function () {
  console.log("====== f_Retrieve ==================");
  let ret = await $c.gus.cfValidate($p, [ica_fromDate, ed_sacctDeptCd, ed_coCd]);
  if (!ret) {
    return false;
  }
  if (ica_fromDate.getValue().length != 6) {
    await $c.win.alert($p, "마감년월은(는) 6자리수만큼 입력하십시오.");
    ica_fromDate.focus();
    return;
  }
  ret = await $c.date.isDate($p, ica_fromDate.getValue() + "01");
  if (!ret) {
    await $c.win.alert($p, "올바른 마감년월을(를) 입력하십시오.");
    ica_fromDate.focus();
    return;
  }
  scwin.setInit();
  var dcJSON = dma_search.getJSON();
  console.log("  *** dma_search : " + JSON.stringify(dcJSON));
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_retrieve_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  gr_mgntPrfloss.setNoResultMessageVisible(true);
  let rowCnt = ds_mgntPrfloss.getRowCount();
  totalRows.setValue(rowCnt);
  if (rowCnt > 0) {
    ds_mgntPrfloss.reform();
    gr_mgntPrfloss.setFocusedCell(0, 0);
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
  }
  //저장가능상태로 Flag변경함.
  ica_fromDate.hidVal = ica_fromDate.getValue();
  lc_version.hidVal = lc_version.getValue();
  scwin.check_select = true;
};

