/**
 * 저장버튼
 */
scwin.f_Save = async function () {
  console.log("=========== f_Save (저장) === check_select [" + scwin.check_select + "]");
  if (!scwin.check_select) {
    await $c.win.alert($p, "조회 조건인 마감년월과 버젼이 변경되어서 저장 하실 수 없습니다.<BR>재 조회 후 저장 하시기 바랍니다.");
    return;
  }
  let ret = await $c.gus.cfValidate($p, [gr_mgntPrfloss]);
  if (!ret) {
    return false;
  }

  //변경한 데이터가 있는지 체크한다.
  // if (ds_mgntPrfloss.IsUpdated == false) {
  if (ds_mgntPrfloss.getModifiedIndex().length < 1) {
    // MSG_CM_ERR_001   = "@은(는) 변경된 사항이 없습니다."
    await $c.gus.cfAlertMsg($p, $c.data.getMessage($p, MSG_CM_ERR_001, "자료"));
    return;
  }
  if ($c.gus.cfIsNull($p, lc_version.getValue())) {
    await $c.win.alert($p, "해당 년월의 버전정보가 없습니다.<BR>관리실적버전에서 버전을 등록하시기 바랍니다.");
    return;
  }
  if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
    sbm_save.userData1 = "noError";
    $c.sbm.execute($p, sbm_save);
  }
};
